      | `TooManyTagsError of TooManyTagsError.t 
      | `TooManyUpdates of TooManyUpdates.t 
      | `Unknown_operation_error of (string * string option) ]
    let make () = ()
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "InvalidResourceId" ->
          `InvalidResourceId (InvalidResourceId.of_json json)
      | "InvalidResourceType" ->
          `InvalidResourceType (InvalidResourceType.of_json json)
      | "TooManyTagsError" ->
          `TooManyTagsError (TooManyTagsError.of_json json)
      | "TooManyUpdates" -> `TooManyUpdates (TooManyUpdates.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "InvalidResourceId" ->
          `InvalidResourceId (InvalidResourceId.of_xml xml)
      | "InvalidResourceType" ->
          `InvalidResourceType (InvalidResourceType.of_xml xml)
      | "TooManyTagsError" -> `TooManyTagsError (TooManyTagsError.of_xml xml)
      | "TooManyUpdates" -> `TooManyUpdates (TooManyUpdates.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `InvalidResourceId e ->
          `Assoc
            [("error", (`String "InvalidResourceId"));
            ("details", (InvalidResourceId.to_json e))]
      | `InvalidResourceType e ->
          `Assoc
            [("error", (`String "InvalidResourceType"));
            ("details", (InvalidResourceType.to_json e))]
      | `TooManyTagsError e ->
          `Assoc
            [("error", (`String "TooManyTagsError"));
            ("details", (TooManyTagsError.to_json e))]
      | `TooManyUpdates e ->
          `Assoc
            [("error", (`String "TooManyUpdates"));
            ("details", (TooManyUpdates.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let of_header_and_body = ((fun (xs, pipe) -> make ())[@warning "-27"])
    let to_value _ = `Structure []
    let to_query v = to_query to_value v
