module AutomationExecutionStatus =
  struct
    type nonrec t =
      | Pending 
      | InProgress 
      | Waiting 
      | Success 
      | TimedOut 
      | Cancelling 
      | Cancelled 
      | Failed 
      | PendingApproval 
      | Approved 
      | Rejected 
      | Scheduled 
      | RunbookInProgress 
      | PendingChangeCalendarOverride 
      | ChangeCalendarOverrideApproved 
      | ChangeCalendarOverrideRejected 
      | CompletedWithSuccess 
      | CompletedWithFailure 
      | Exited 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Pending -> "Pending"
      | InProgress -> "InProgress"
      | Waiting -> "Waiting"
      | Success -> "Success"
      | TimedOut -> "TimedOut"
      | Cancelling -> "Cancelling"
      | Cancelled -> "Cancelled"
      | Failed -> "Failed"
      | PendingApproval -> "PendingApproval"
      | Approved -> "Approved"
      | Rejected -> "Rejected"
      | Scheduled -> "Scheduled"
      | RunbookInProgress -> "RunbookInProgress"
      | PendingChangeCalendarOverride -> "PendingChangeCalendarOverride"
      | ChangeCalendarOverrideApproved -> "ChangeCalendarOverrideApproved"
      | ChangeCalendarOverrideRejected -> "ChangeCalendarOverrideRejected"
      | CompletedWithSuccess -> "CompletedWithSuccess"
      | CompletedWithFailure -> "CompletedWithFailure"
      | Exited -> "Exited"
      | Non_static_id s -> s
    let of_string =
      function
      | "Pending" -> Pending
      | "InProgress" -> InProgress
      | "Waiting" -> Waiting
      | "Success" -> Success
      | "TimedOut" -> TimedOut
      | "Cancelling" -> Cancelling
      | "Cancelled" -> Cancelled
      | "Failed" -> Failed
      | "PendingApproval" -> PendingApproval
      | "Approved" -> Approved
      | "Rejected" -> Rejected
      | "Scheduled" -> Scheduled
      | "RunbookInProgress" -> RunbookInProgress
      | "PendingChangeCalendarOverride" -> PendingChangeCalendarOverride
      | "ChangeCalendarOverrideApproved" -> ChangeCalendarOverrideApproved
      | "ChangeCalendarOverrideRejected" -> ChangeCalendarOverrideRejected
      | "CompletedWithSuccess" -> CompletedWithSuccess
      | "CompletedWithFailure" -> CompletedWithFailure
      | "Exited" -> Exited
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration AutomationExecutionStatus" xml_arg0)
