module CreateActivationResult =
  struct
    type nonrec t =
      {
      activationId: ActivationId.t option
        [@ocaml.doc
          "The ID number generated by the system when it processed the activation. The activation ID functions like a user name."];
      activationCode: ActivationCode.t option
        [@ocaml.doc
          "The code the system generates when it processes the activation. The activation code functions like a password to validate the activation ID."]}
    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `InvalidParameters of InvalidParameters.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?activationId =
      fun ?activationCode -> fun () -> { activationId; activationCode }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "InvalidParameters" ->
          `InvalidParameters (InvalidParameters.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "InvalidParameters" ->
          `InvalidParameters (InvalidParameters.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `InvalidParameters e ->
          `Assoc
            [("error", (`String "InvalidParameters"));
            ("details", (InvalidParameters.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("ActivationId",
           (Option.map x.activationId ~f:ActivationId.to_value));
        ("ActivationCode",
          (Option.map x.activationCode ~f:ActivationCode.to_value))]
