      | "InvalidSchedule" -> `InvalidSchedule (InvalidSchedule.of_json json)
      | "InvalidTarget" -> `InvalidTarget (InvalidTarget.of_json json)
      | "InvalidTargetMaps" ->
          `InvalidTargetMaps (InvalidTargetMaps.of_json json)
