      match name with
      | "AssociationLimitExceeded" ->
          `AssociationLimitExceeded (AssociationLimitExceeded.of_xml xml)
      | "DuplicateInstanceId" ->
          `DuplicateInstanceId (DuplicateInstanceId.of_xml xml)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "InvalidDocument" -> `InvalidDocument (InvalidDocument.of_xml xml)
      | "InvalidDocumentVersion" ->
          `InvalidDocumentVersion (InvalidDocumentVersion.of_xml xml)
      | "InvalidInstanceId" ->
          `InvalidInstanceId (InvalidInstanceId.of_xml xml)
      | "InvalidOutputLocation" ->
          `InvalidOutputLocation (InvalidOutputLocation.of_xml xml)
      | "InvalidParameters" ->
          `InvalidParameters (InvalidParameters.of_xml xml)
      | "InvalidSchedule" -> `InvalidSchedule (InvalidSchedule.of_xml xml)
      | "InvalidTarget" -> `InvalidTarget (InvalidTarget.of_xml xml)
      | "InvalidTargetMaps" ->
          `InvalidTargetMaps (InvalidTargetMaps.of_xml xml)
      | "UnsupportedPlatformType" ->
          `UnsupportedPlatformType (UnsupportedPlatformType.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AssociationLimitExceeded e ->
          `Assoc
            [("error", (`String "AssociationLimitExceeded"));
            ("details", (AssociationLimitExceeded.to_json e))]
      | `DuplicateInstanceId e ->
          `Assoc
            [("error", (`String "DuplicateInstanceId"));
            ("details", (DuplicateInstanceId.to_json e))]
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `InvalidDocument e ->
          `Assoc
            [("error", (`String "InvalidDocument"));
            ("details", (InvalidDocument.to_json e))]
      | `InvalidDocumentVersion e ->
          `Assoc
            [("error", (`String "InvalidDocumentVersion"));
            ("details", (InvalidDocumentVersion.to_json e))]
      | `InvalidInstanceId e ->
          `Assoc
            [("error", (`String "InvalidInstanceId"));
            ("details", (InvalidInstanceId.to_json e))]
      | `InvalidOutputLocation e ->
          `Assoc
            [("error", (`String "InvalidOutputLocation"));
            ("details", (InvalidOutputLocation.to_json e))]
      | `InvalidParameters e ->
          `Assoc
            [("error", (`String "InvalidParameters"));
            ("details", (InvalidParameters.to_json e))]
      | `InvalidSchedule e ->
          `Assoc
            [("error", (`String "InvalidSchedule"));
            ("details", (InvalidSchedule.to_json e))]
      | `InvalidTarget e ->
          `Assoc
            [("error", (`String "InvalidTarget"));
            ("details", (InvalidTarget.to_json e))]
      | `InvalidTargetMaps e ->
