          `DocumentLimitExceeded (DocumentLimitExceeded.of_json json)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "InvalidDocumentContent" ->
          `InvalidDocumentContent (InvalidDocumentContent.of_json json)
      | "InvalidDocumentSchemaVersion" ->
          `InvalidDocumentSchemaVersion
            (InvalidDocumentSchemaVersion.of_json json)
