            ("details", (MaxDocumentSizeExceeded.to_json e))]
      | `NoLongerSupportedException e ->
          `Assoc
            [("error", (`String "NoLongerSupportedException"));
            ("details", (NoLongerSupportedException.to_json e))]
      | `TooManyUpdates e ->
