      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "ResourceLimitExceededException" ->
          `ResourceLimitExceededException
            (ResourceLimitExceededException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "IdempotentParameterMismatch" ->
          `IdempotentParameterMismatch
            (IdempotentParameterMismatch.of_xml xml)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "ResourceLimitExceededException" ->
          `ResourceLimitExceededException
            (ResourceLimitExceededException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `IdempotentParameterMismatch e ->
          `Assoc
            [("error", (`String "IdempotentParameterMismatch"));
            ("details", (IdempotentParameterMismatch.to_json e))]
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `ResourceLimitExceededException e ->
          `Assoc
            [("error", (`String "ResourceLimitExceededException"));
            ("details", (ResourceLimitExceededException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
