    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `ResourceDataSyncAlreadyExistsException of
          ResourceDataSyncAlreadyExistsException.t 
      | `ResourceDataSyncCountExceededException of
          ResourceDataSyncCountExceededException.t 
      | `ResourceDataSyncInvalidConfigurationException of
          ResourceDataSyncInvalidConfigurationException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make () = ()
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "ResourceDataSyncAlreadyExistsException" ->
          `ResourceDataSyncAlreadyExistsException
            (ResourceDataSyncAlreadyExistsException.of_json json)
      | "ResourceDataSyncCountExceededException" ->
          `ResourceDataSyncCountExceededException
            (ResourceDataSyncCountExceededException.of_json json)
      | "ResourceDataSyncInvalidConfigurationException" ->
          `ResourceDataSyncInvalidConfigurationException
            (ResourceDataSyncInvalidConfigurationException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "ResourceDataSyncAlreadyExistsException" ->
          `ResourceDataSyncAlreadyExistsException
            (ResourceDataSyncAlreadyExistsException.of_xml xml)
      | "ResourceDataSyncCountExceededException" ->
          `ResourceDataSyncCountExceededException
            (ResourceDataSyncCountExceededException.of_xml xml)
      | "ResourceDataSyncInvalidConfigurationException" ->
          `ResourceDataSyncInvalidConfigurationException
            (ResourceDataSyncInvalidConfigurationException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `ResourceDataSyncAlreadyExistsException e ->
          `Assoc
            [("error", (`String "ResourceDataSyncAlreadyExistsException"));
            ("details", (ResourceDataSyncAlreadyExistsException.to_json e))]
      | `ResourceDataSyncCountExceededException e ->
          `Assoc
            [("error", (`String "ResourceDataSyncCountExceededException"));
            ("details", (ResourceDataSyncCountExceededException.to_json e))]
      | `ResourceDataSyncInvalidConfigurationException e ->
          `Assoc
            [("error",
               (`String "ResourceDataSyncInvalidConfigurationException"));
            ("details",
              (ResourceDataSyncInvalidConfigurationException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
